-- Haul Command aggressive AdGrid + Data Monetization build scaffold
-- Generated: 2026-05-29
-- Purpose: Non-destructive Supabase planning/build-contract layer for Codex.
-- Boundary: AdGrid remains internal to Haul Command-owned surfaces. External ad activity = retargeting/audience recovery only.
-- Apply with: supabase db push OR paste into Supabase SQL editor.

begin;

create schema if not exists hc_build;
comment on schema hc_build is 'Codex-facing build contracts for Haul Command AdGrid, data monetization, media factory, competitor displacement, and Google/Reddit/Meta-inspired internal ad upgrades. Non-destructive planning schema.';

create table if not exists hc_build.codex_programs (
  program_key text primary key,
  program_name text not null,
  product_area text not null,
  priority integer not null default 50 check (priority between 1 and 100),
  status text not null default 'planned' check (status in ('planned','ready_for_codex','in_build','blocked','shipped','deferred')),
  launch_phase text not null default 'phase_1',
  mission text not null,
  hard_boundaries jsonb not null default '{}'::jsonb,
  source_inspiration jsonb not null default '[]'::jsonb,
  codex_directive text not null,
  acceptance_summary text not null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
comment on table hc_build.codex_programs is 'Top-level build programs that Codex should read before generating code. These are product contracts, not runtime event tables.';

create table if not exists hc_build.codex_feature_specs (
  feature_key text primary key,
  program_key text not null references hc_build.codex_programs(program_key) on delete cascade,
  feature_name text not null,
  product_area text not null,
  priority integer not null default 50 check (priority between 1 and 100),
  build_stage text not null default 'scaffolded',
  monetization_model text not null,
  why_now text not null,
  target_surfaces jsonb not null default '[]'::jsonb,
  event_sources jsonb not null default '[]'::jsonb,
  data_monetization_effect jsonb not null default '{}'::jsonb,
  required_existing_objects jsonb not null default '[]'::jsonb,
  new_objects_to_build jsonb not null default '[]'::jsonb,
  core_spec jsonb not null default '{}'::jsonb,
  guardrails jsonb not null default '[]'::jsonb,
  codex_directive text not null,
  acceptance_criteria jsonb not null default '[]'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
comment on table hc_build.codex_feature_specs is 'Feature-level build contracts, acceptance criteria, monetization logic, and data-product implications.';

create table if not exists hc_build.codex_build_tasks (
  task_key text primary key,
  feature_key text references hc_build.codex_feature_specs(feature_key) on delete set null,
  sprint text not null default 'adgrid_data_monetization_war_room',
  priority integer not null default 50 check (priority between 1 and 100),
  task_type text not null,
  task_title text not null,
  action_summary text not null,
  depends_on jsonb not null default '[]'::jsonb,
  db_objects jsonb not null default '[]'::jsonb,
  app_surfaces jsonb not null default '[]'::jsonb,
  acceptance_tests jsonb not null default '[]'::jsonb,
  monetization_impact text not null,
  ready_for_codex boolean not null default true,
  status text not null default 'open' check (status in ('open','in_progress','blocked','done','deferred')),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
comment on table hc_build.codex_build_tasks is 'Concrete Codex tickets generated from the strategy conversation. Codex should implement in priority order.';

create table if not exists hc_build.platform_inspiration_specs (
  inspiration_key text primary key,
  platform_name text not null,
  pattern_name text not null,
  current_signal text not null,
  haul_command_adaptation text not null,
  do_not_copy text not null,
  codex_translation jsonb not null default '{}'::jsonb,
  source_urls jsonb not null default '[]'::jsonb,
  priority integer not null default 50,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
comment on table hc_build.platform_inspiration_specs is 'Ethical product patterns from Google, Reddit, Meta, Yellow Pages, Motion, and ad-intelligence tools translated into Haul Command-native internal products.';

create table if not exists hc_build.adgrid_surface_taxonomy (
  surface_key text primary key,
  surface_family text not null,
  surface_name text not null,
  monetizable boolean not null default true,
  supports_house_ads boolean not null default true,
  supports_paid_sponsors boolean not null default true,
  supports_call_ads boolean not null default false,
  supports_sponsored_answers boolean not null default false,
  supports_data_signal_capture boolean not null default true,
  recommended_ad_products jsonb not null default '[]'::jsonb,
  required_events jsonb not null default '[]'::jsonb,
  data_products_fed jsonb not null default '[]'::jsonb,
  notes text not null default '',
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
comment on table hc_build.adgrid_surface_taxonomy is 'Canonical Haul Command-owned surfaces where internal AdGrid inventory can live. No external open ad network surfaces belong here.';

create table if not exists hc_build.adgrid_event_policy (
  event_key text primary key,
  event_family text not null,
  event_name text not null,
  privacy_level text not null check (privacy_level in ('public_aggregate','private_raw','restricted_sensitive','do_not_sell')),
  revenue_use text not null,
  data_product_use text not null,
  aggregation_rule text not null,
  minimum_k_anonymity integer not null default 10,
  required_fields jsonb not null default '[]'::jsonb,
  prohibited_fields jsonb not null default '[]'::jsonb,
  codex_directive text not null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
comment on table hc_build.adgrid_event_policy is 'Dual-purpose event policy: every AdGrid event improves ads and, if legally allowed, powers anonymized/aggregated data products.';

create table if not exists hc_build.data_product_blueprints (
  data_product_key text primary key,
  product_name text not null,
  product_family text not null,
  priority integer not null default 50,
  launch_phase text not null default 'phase_1',
  buyer_personas jsonb not null default '[]'::jsonb,
  input_signals jsonb not null default '[]'::jsonb,
  output_formats jsonb not null default '[]'::jsonb,
  pricing_model jsonb not null default '{}'::jsonb,
  privacy_gate text not null,
  self_serve_requirements jsonb not null default '[]'::jsonb,
  codex_directive text not null,
  acceptance_criteria jsonb not null default '[]'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
comment on table hc_build.data_product_blueprints is 'Self-serve data monetization products connected to AdGrid, directory, corridor, load, community, and media signals across 120 countries.';

create table if not exists hc_build.media_factory_blueprints (
  media_asset_key text primary key,
  asset_name text not null,
  production_engine text not null check (production_engine in ('hyperframes','remotion','heygen_minimal','manual_upload','mixed')),
  priority integer not null default 50,
  feeds_adgrid boolean not null default true,
  feeds_data_products boolean not null default true,
  asset_spec jsonb not null default '{}'::jsonb,
  adgrid_usage jsonb not null default '[]'::jsonb,
  data_signal_usage jsonb not null default '[]'::jsonb,
  codex_directive text not null,
  acceptance_criteria jsonb not null default '[]'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
comment on table hc_build.media_factory_blueprints is 'Media Factory contract: HyperFrames/Remotion/limited HeyGen creates assets; AdGrid places, prices, tests, and measures them.';

create table if not exists hc_build.competitor_displacement_targets (
  target_key text primary key,
  competitor_family text not null,
  competitor_name text not null,
  what_they_win text not null,
  what_they_lack text not null,
  haul_command_countermove text not null,
  moats_to_build jsonb not null default '[]'::jsonb,
  signals_to_monitor jsonb not null default '[]'::jsonb,
  products_to_launch jsonb not null default '[]'::jsonb,
  priority integer not null default 50,
  codex_directive text not null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
comment on table hc_build.competitor_displacement_targets is 'Competitor-displacement playbooks for Google, Reddit, Meta/Facebook, Yellow Pages/Yelp, freight boards, niche directories, and AI ad platforms.';

create table if not exists hc_build.missing_money_radar (
  opportunity_key text primary key,
  opportunity_name text not null,
  product_area text not null,
  priority integer not null default 50,
  revenue_lever text not null,
  current_gap text not null,
  aggressive_move text not null,
  required_signals jsonb not null default '[]'::jsonb,
  expected_outputs jsonb not null default '[]'::jsonb,
  codex_directive text not null,
  acceptance_criteria jsonb not null default '[]'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
comment on table hc_build.missing_money_radar is 'Aggressive list of money-left-on-table opportunities to force Codex/product planning to prioritize revenue loops.';

create table if not exists hc_build.proof_packet_blueprints (
  proof_packet_key text primary key,
  packet_name text not null,
  sponsor_product_family text not null,
  priority integer not null default 50,
  included_metrics jsonb not null default '[]'::jsonb,
  included_visuals jsonb not null default '[]'::jsonb,
  renewal_recommendations jsonb not null default '[]'::jsonb,
  data_monetization_secondary_use text not null,
  codex_directive text not null,
  acceptance_criteria jsonb not null default '[]'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
comment on table hc_build.proof_packet_blueprints is 'Sponsor proof packets: every AdGrid product should prove value and produce renewal/upsell recommendations.';

create table if not exists hc_build.launch_phase_gates (
  gate_key text primary key,
  launch_phase text not null,
  gate_name text not null,
  product_area text not null,
  priority integer not null default 50,
  pass_condition text not null,
  required_objects jsonb not null default '[]'::jsonb,
  required_metrics jsonb not null default '[]'::jsonb,
  failure_response text not null,
  codex_directive text not null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
comment on table hc_build.launch_phase_gates is 'Launch gates for first-three-products: AdGrid, self-serve data monetization, and connected paid lead/claim products.';

create index if not exists idx_hc_build_programs_priority on hc_build.codex_programs(priority desc, status, product_area);
create index if not exists idx_hc_build_features_priority on hc_build.codex_feature_specs(priority desc, product_area, build_stage);
create index if not exists idx_hc_build_tasks_priority on hc_build.codex_build_tasks(priority desc, status, ready_for_codex);
create index if not exists idx_hc_build_data_products_priority on hc_build.data_product_blueprints(priority desc, launch_phase);
create index if not exists idx_hc_build_missing_money_priority on hc_build.missing_money_radar(priority desc, product_area);
create index if not exists idx_hc_build_event_policy_family on hc_build.adgrid_event_policy(event_family, privacy_level);


insert into hc_build.codex_programs (program_key, program_name, product_area, priority, status, launch_phase, mission, hard_boundaries, source_inspiration, codex_directive, acceptance_summary) values
  ('adgrid_motion_intelligence', 'AdGrid Motion Intelligence Layer', 'adgrid', 100, 'ready_for_codex', 'phase_1', 'Turn every internal ad, house ad, sponsor placement, clip, newsletter slot, conversation ad, and HC ASK placement into a tagged, scored, learnable asset.', '{"adgrid_scope": "internal_haul_command_owned_surfaces_only", "external_allowed": ["retargeting", "audience_recovery"], "external_forbidden": ["open_external_ad_network", "selling placements outside Haul Command owned surfaces"]}'::jsonb, '["Motion creative analytics", "Google AI Max/AI Search ads", "Reddit community proof", "Meta AI automation"]'::jsonb, 'Build a command-center layer over existing AdGrid tables that scores creative patterns, detects winners, recommends next actions, and writes buildable insights without replacing existing AdGrid runtime tables.', 'Codex can query winning patterns by role/country/corridor/surface/creative angle and generate action recommendations.'),
  ('adgrid_data_monetization_bridge', 'AdGrid → Self-Serve Data Monetization Bridge', 'data_monetization', 100, 'ready_for_codex', 'phase_1', 'Make AdGrid a demand-signal machine that feeds anonymized, aggregated 120-country data products.', '{"aggregation": "k-anonymity minimum by market/category/time window", "legal_gate": "country-specific data product legal gate required", "privacy": "no sale of individual user-level behavior"}'::jsonb, '["Google first-party measurement", "Reddit Community Intelligence", "Haul Command demand/corridor data spine"]'::jsonb, 'Connect internal event streams to data product blueprints through aggregate signal tables and self-serve export entitlements.', 'Every qualified event has an ad-optimization use and an allowed/blocked data-product use.'),
  ('heavy_haul_call_ads', 'Heavy Haul Call Ads and Qualified Call Leads', 'adgrid', 99, 'ready_for_codex', 'phase_1', 'Own high-intent call demand better than Google by making tap-to-call, pay-per-call, qualified calls, missed-call recovery, and call proof native to heavy haul.', '{"billing": "bill only according to configured qualification policy", "fraud": "spam and duplicate call detection required", "recording": "country/state consent gate required"}'::jsonb, '["Google Ads call assets", "Google call reporting", "Yellow Pages pay-per-call"]'::jsonb, 'Build call ad product specs, call event policy, call quality scoring, routing number abstraction, and sponsor proof metrics.', 'A sponsor can buy call-focused inventory and receive proof of calls, qualified calls, missed calls, outcomes, and recommended next markets.'),
  ('sponsored_hc_ask_answers', 'Sponsored HC ASK Answers', 'search_ai', 98, 'ready_for_codex', 'phase_1', 'Beat Google AI Mode inside heavy haul by putting clearly labeled sponsored answers inside Haul Command search/chat where directory context, role, market, and route intent are known.', '{"answer_quality": "organic answer remains useful", "labeling": "sponsored placements must be explicit", "trust": "no pay-to-lie or hidden placements"}'::jsonb, '["Google AI Overviews ads", "Google AI Mode ads", "Reddit thread-native ads"]'::jsonb, 'Define answer-slot inventory, sponsor matching rules, labeling rules, proof stack, click/call/quote events, and fallback organic behavior.', 'HC ASK can assemble helpful organic answer + labeled sponsor options + call/quote CTAs + data-signal capture.'),
  ('media_factory_breakout_clips', 'Media Factory + Breakout Clip Monetization', 'media_factory', 96, 'ready_for_codex', 'phase_1', 'Make HyperFrames/Remotion create cheap scalable media assets while AdGrid prices, places, tests, and monetizes the assets.', '{"heygen": "use sparingly for trust/talking-head moments only", "ownership": "Media Factory renders assets; AdGrid never becomes video renderer"}'::jsonb, '["Breakout Clips", "HyperFrames", "Remotion", "Meta generative ad automation"]'::jsonb, 'Create asset blueprint and performance ledger specs for clips, sponsor cards, market recaps, proof visuals, and localized variants.', 'Every breakout clip can become content, AdGrid inventory, sponsor proof, retargeting audience seed, and data product signal.'),
  ('community_intelligence', 'Heavy Haul Community Intelligence', 'community_data', 95, 'ready_for_codex', 'phase_1', 'Beat Reddit by turning Haul Command threads, Q&A, reviews, comments, clips, and directory behavior into trusted structured ecosystem intelligence.', '{"moderation": "do not surface unsafe or defamatory content as proof", "privacy": "aggregate public/community signals; no private DMs sold"}'::jsonb, '["Reddit Community Intelligence", "Reddit Conversation Summary Add-ons"]'::jsonb, 'Build positive proof stack, pain-point extraction, sponsor-safe summaries, and community trend data products.', 'Sponsor ads and data products can cite aggregated community proof without exposing private users.'),
  ('self_serve_ai_campaign_builder', 'Self-Serve AI Campaign Builder', 'adgrid', 94, 'ready_for_codex', 'phase_1', 'Let any sponsor enter service area, budget, goal, phone, category, and offer; AdGrid builds internal placements, creative variants, bid/floor recommendations, and proof packets.', '{"brand_safety": "avoid Meta-style uncontrolled creative drift", "control": "human sponsor can review/approve before launch"}'::jsonb, '["Meta AI ad automation", "Google agentic capabilities", "Motion what-to-make-next AI"]'::jsonb, 'Create wizard spec, recommendation outputs, generated campaign assets, target inventory selection, and safeguards.', 'Sponsor can generate a campaign package without knowing ad jargon.'),
  ('competitor_displacement_layer', 'Competitor Displacement Layer', 'growth_intelligence', 93, 'ready_for_codex', 'phase_1', 'Identify who is buying or owning heavy-haul attention and build moats before they see Haul Command coming.', '{"copying": "do not copy ads verbatim; extract patterns and beat them", "ethics": "use public/legal competitive intelligence only"}'::jsonb, '["Google Ads Transparency Center", "Meta Ad Library", "Semrush/SpyFu/Adthena pattern", "niche directories"]'::jsonb, 'Build competitor target records, gap scoring, displacement recommendations, and sponsor/offering counter-moves.', 'Codex can show what competitor family is winning, what they lack, and what HC product closes the gap.'),
  ('category_location_engine_120', 'Yellow Pages 100X Category × Location Engine', 'directory_adgrid_data', 92, 'ready_for_codex', 'phase_1', 'Turn every role/category/location combination across 120 countries into directory inventory, SEO/AEO surface, AdGrid slot, and data product row.', '{"compliance": "country-specific legal/data gates", "quality": "only index pages with enough evidence/coverage or honest scarcity labeling"}'::jsonb, '["Yellow Pages category/location model", "Google Local Services Ads", "Haul Command 120-country spine"]'::jsonb, 'Seed the contract for category/location monetization, sponsor exclusivity, proof, and data products.', 'Each category-location cell can be evaluated for SEO, sponsor, data, and supply gap readiness.'),
  ('retargeting_recovery_layer', 'External Retargeting Recovery Layer', 'retargeting', 90, 'ready_for_codex', 'phase_1', 'Use outside networks only to bring Haul Command visitors back into the directory, claim flow, sponsor checkout, data portal, or lead product.', '{"external_scope": "retargeting only", "privacy": "consent, country eligibility, and platform policy gates required"}'::jsonb, '["Google/Meta retargeting", "first-party audience recovery"]'::jsonb, 'Define audiences, event eligibility, suppression, campaign intents, and return-to-HC CTAs.', 'Retargeting never becomes external AdGrid; it only recovers abandoned/qualified HC intent.'),
  ('sponsor_proof_packets', 'Universal Sponsor Proof Packets', 'adgrid', 89, 'ready_for_codex', 'phase_1', 'Make every sponsor renewal easier by proving where ads ran, what happened, what improved, and what to buy next.', '{"privacy": "show sponsor aggregate/business-level proof, not private user logs", "truth": "do not inflate metrics"}'::jsonb, '["Motion reporting", "Google campaign reporting", "Reddit proof under ads"]'::jsonb, 'Create proof packet blueprints for call ads, directory sponsors, HC ASK answers, clips, newsletters, takeovers, AMA/events, and direct offers.', 'Every paid product has a proof-packet template with renewal recommendations.'),
  ('data_product_self_serve_portal', '120-Country Self-Serve Data Product Portal', 'data_monetization', 88, 'ready_for_codex', 'phase_1', 'Launch data monetization as a first-three product with self-serve browsing, previews, export jobs, API keys, entitlements, and legal gates.', '{"freshness": "show coverage, confidence, date, and provenance", "privacy": "aggregated/allowed data only"}'::jsonb, '["Google measurement/reporting", "Reddit Insights", "Haul Command data product spine"]'::jsonb, 'Use existing data product/export/API-key tables where available; add app routes and UI using these blueprints.', 'Buyer can self-serve country/category/corridor reports with preview, purchase, export/API access, and confidence/freshness labels.')
on conflict (program_key) do update set program_name=excluded.program_name, product_area=excluded.product_area, priority=excluded.priority, status=excluded.status, launch_phase=excluded.launch_phase, mission=excluded.mission, hard_boundaries=excluded.hard_boundaries, source_inspiration=excluded.source_inspiration, codex_directive=excluded.codex_directive, acceptance_summary=excluded.acceptance_summary;

insert into hc_build.codex_feature_specs (feature_key, program_key, feature_name, product_area, priority, build_stage, monetization_model, why_now, target_surfaces, event_sources, data_monetization_effect, required_existing_objects, new_objects_to_build, core_spec, guardrails, codex_directive, acceptance_criteria) values
  ('adgrid_internal_scope_lock', 'adgrid_motion_intelligence', 'Internal AdGrid Scope Lock', 'adgrid', 100, 'contract', 'Prevents drift; keeps all sponsor dollars tied to Haul Command-owned inventory.', 'User clarified AdGrid is Google Ads only inside the HC directory/ecosystem, with external retargeting only.', '["all_adgrid_surfaces"]'::jsonb, '["all_adgrid_events"]'::jsonb, '{"effect": "clean boundary for event policy and sales collateral"}'::jsonb, '["hc_adgrid_*", "ad_* tables where present"]'::jsonb, '["adgrid boundary checks", "admin copy updates"]'::jsonb, '{"must_enforce": ["internal owned surfaces only", "external retargeting only", "no open external publisher network"]}'::jsonb, '["Never pitch AdGrid as external network", "Do not create outside publisher inventory"]'::jsonb, 'Add product copy, admin constants, and tests that enforce AdGrid internal-only positioning.', '["AdGrid UI/copy says internal ecosystem ads", "Retargeting is a separate product area", "No model names external publisher inventory as AdGrid inventory"]'::jsonb),
  ('dual_purpose_event_policy', 'adgrid_data_monetization_bridge', 'Dual-Purpose AdGrid Event Policy', 'data_monetization', 100, 'contract', 'Each event improves ads and creates eligible aggregated data products.', 'AdGrid and self-serve data monetization launch early together; signals must be captured right from day one.', '["directory", "hc_ask", "threads", "clips", "newsletter", "load_board", "data_portal"]'::jsonb, '["impressions", "clicks", "calls", "claims", "leads", "hides", "reports", "profile_views", "clip_events"]'::jsonb, '{"products": ["demand indexes", "call-intent benchmarks", "sponsor opportunity maps", "scarcity reports"]}'::jsonb, '["hc_data_products", "hc_data_bundles", "hc_data_product_export_jobs", "hc_data_api_keys", "v_data_product_legal_gate"]'::jsonb, '["aggregate signal marts", "privacy gate service", "data product preview API"]'::jsonb, '{"default_privacy": "aggregate only", "minimum_k": 10, "raw_storage": "private/restricted"}'::jsonb, '["No individual-level user data product", "Country legal gate before export", "Freshness/confidence/provenance labels required"]'::jsonb, 'Implement aggregate marts and data-product eligibility checks using this policy as the source of truth.', '["Every event has revenue_use and data_product_use", "Exports block if privacy gate fails", "Previews show coverage/confidence/freshness"]'::jsonb),
  ('creative_pattern_library', 'adgrid_motion_intelligence', 'Creative Pattern Library', 'adgrid', 98, 'contract', 'Clone winning creative angles across 120 countries and sponsor categories.', 'Motion-style intelligence should sit on top of existing A/B tests and creative framework fields.', '["directory", "conversation_ads", "newsletter", "clips", "hc_ask", "house_ads"]'::jsonb, '["ab_tests", "impressions", "clicks", "leads", "calls", "claims", "hides", "reports"]'::jsonb, '{"secondary_products": ["adgrid_roi_benchmarks", "sponsor category benchmarks"]}'::jsonb, '["hc_adgrid_ab_tests", "hc_adgrid_campaign", "hc_adgrid_house_ad_templates"]'::jsonb, '["pattern scorer", "next move recommender", "creative angle tagging"]'::jsonb, '{"angles": ["urgent load", "missed money", "dispatch ready", "certified trust", "scarce supply", "local specialist", "corridor dominance", "country takeover", "compliance confidence", "route ready equipment", "fast pay", "sponsor this market"]}'::jsonb, '["Do not auto-publish unreviewed paid sponsor creative", "Maintain sponsor brand controls"]'::jsonb, 'Build tagging and scoring adapters over existing campaign/creative tables; expose top patterns by market/surface/role.', '["Can query winning angles", "Can recommend clone/kill/rewrite/sponsor/localize", "Can attach pattern to proof packet"]'::jsonb),
  ('heavy_haul_call_ads', 'heavy_haul_call_ads', 'Heavy Haul Call Ads', 'adgrid', 99, 'contract', 'Pay-per-call, qualified-call, urgent-call, exclusive-call, and call-focused sponsor packages.', 'Google call assets/call reporting prove call intent is high value; HC can add heavy-haul context Google lacks.', '["directory", "city_page", "corridor_page", "hc_ask", "mobile_profile", "retargeting_landing"]'::jsonb, '["call_tap", "call_connected", "call_duration", "qualified_call", "missed_call", "call_outcome"]'::jsonb, '{"products": ["call intent index", "category response benchmarks", "missed demand report"]}'::jsonb, '["hc_adgrid_campaign", "hc_adgrid_outcome_events", "directory/provider profiles"]'::jsonb, '["call product specs", "routing number abstraction", "qualified-call rules", "missed-call recovery queue"]'::jsonb, '{"pricing": ["cpc_call_tap", "pay_per_qualified_call", "exclusive_call_lead", "monthly call sponsor"], "qualification": ["duration threshold", "unique caller window", "role/category match", "business-hours match", "spam filter", "manual outcome override"]}'::jsonb, '["Consent/legal gate for recording/transcripts", "No sale of raw call recordings as data product", "Verify phone represents sponsor"]'::jsonb, 'Build call ads as first-class AdGrid product with event capture, billing hooks, and proof metrics.', '["Call CTA works on mobile/desktop", "Business-hour schedule supported", "Qualified calls can be billed/proven", "Missed calls create recovery tasks"]'::jsonb),
  ('sponsored_hc_ask_answers', 'sponsored_hc_ask_answers', 'Sponsored HC ASK Answers', 'search_ai', 98, 'contract', 'Sponsored answer slots, call/quote CTAs, market/category sponsorships, direct offers.', 'Google is bringing ads to AI Overviews and AI Mode; HC must own AI search for heavy haul before Google commoditizes it.', '["hc_ask", "ai_search", "directory_search", "glossary_answers", "route_questions"]'::jsonb, '["answer_view", "sponsor_card_view", "call_tap", "quote_request", "profile_click", "hide_report"]'::jsonb, '{"products": ["ai-search demand report", "question intent atlas", "sponsor opportunity map"]}'::jsonb, '["search/ask surface", "directory profiles", "hc_adgrid_campaign"]'::jsonb, '["answer slot policy", "sponsored label component", "organic+sponsored assembly", "answer event schema"]'::jsonb, '{"answer_parts": ["organic useful answer", "verified directory results", "clearly labeled sponsors", "call/quote CTA", "proof stack", "data signal logging"]}'::jsonb, '["Clear sponsored label", "Never degrade safety/compliance answer", "Do not hide organic answer behind payment"]'::jsonb, 'Create answer-slot inventory and matching rules that use role/country/corridor/category intent.', '["Sponsored answers are labeled", "Organic answer remains present", "Events feed AdGrid and data monetization", "Poor quality sponsors can be suppressed"]'::jsonb),
  ('direct_offers', 'sponsored_hc_ask_answers', 'AdGrid Direct Offers', 'adgrid', 93, 'contract', 'Time-boxed discounts, market launches, category promotions, sponsor checkout recovery.', 'AI search/commercial answers are moving toward direct action; HC should sell offers at the point of intent.', '["hc_ask", "directory", "clips", "newsletter", "retargeting", "sponsor_dashboard"]'::jsonb, '["offer_view", "offer_click", "offer_claim", "purchase", "lead_unlock"]'::jsonb, '{"products": ["offer demand benchmarks", "category price response report"]}'::jsonb, '["adgrid campaigns", "billing/orders/entitlements"]'::jsonb, '["offer object", "eligibility/schedule rules", "market/country gates"]'::jsonb, '{"offer_types": ["discount", "sponsor this market", "claim upgrade", "route ready kit", "permit rush quote", "exclusive lead unlock", "install appointment"]}'::jsonb, '["Expiration visible", "Terms visible", "No deceptive scarcity"]'::jsonb, 'Define direct offer model and render path for AdGrid surfaces.', '["Offer can target market/category/role", "Offer has expiration/terms", "Offer conversion is tracked"]'::jsonb),
  ('smart_slot_assembly', 'adgrid_motion_intelligence', 'Smart Slot Assembly', 'adgrid', 91, 'contract', 'Higher CTR/CVR by assembling the right CTA/proof/format per user intent and surface.', 'Google assets appear selectively based on context; HC needs similar internal assembly, but with heavy-haul intent.', '["directory", "mobile", "desktop", "hc_ask", "threads", "clips"]'::jsonb, '["impression", "asset_variant", "click", "call", "lead", "hide"]'::jsonb, '{"products": ["slot performance benchmarks", "surface ROI report"]}'::jsonb, '["hc_adgrid_slots", "hc_adgrid_page_slots", "hc_adgrid_relevance_signals"]'::jsonb, '["slot assembly service", "asset component scoring", "fallback house-ad rules"]'::jsonb, '{"components": ["headline", "proof", "CTA", "call button", "map/city tag", "sponsor badge", "rating", "urgency", "offer", "clip", "compliance badge", "corridor relevance"]}'::jsonb, '["Must respect sponsor approvals", "Must keep sponsor label"]'::jsonb, 'Build rules that choose components by device, market, category, user intent, and historical performance.', '["Mobile call-first assembly supported", "Desktop quote/profile-first assembly supported", "Fallback house ad fills unsold slots"]'::jsonb),
  ('heavy_haul_quality_score', 'adgrid_motion_intelligence', 'Heavy Haul Ad Quality Score', 'adgrid_trust', 95, 'contract', 'Protects ecosystem trust; improves ad yield by rewarding verified/relevant sponsors.', 'Haul Command must be better than Google by not letting bad sponsors buy trust.', '["all_adgrid_surfaces"]'::jsonb, '["reviews", "claim_status", "response_speed", "call_answer_rate", "complaints", "hide_report", "profile_completeness", "credential_status"]'::jsonb, '{"products": ["trusted supplier benchmarks", "market trust report"]}'::jsonb, '["provider profiles", "reviews/trust/badges", "adgrid campaigns"]'::jsonb, '["quality score dimensions", "suppression thresholds", "score reason API"]'::jsonb, '{"dimensions": ["verified profile", "role fit", "market fit", "response speed", "call answer rate", "complaint rate", "reviews", "credential/badge status", "landing quality", "creative clarity", "corridor relevance", "fulfillment capacity"]}'::jsonb, '["Do not use protected/sensitive attributes", "Provide reason codes", "Allow manual review"]'::jsonb, 'Create quality score adapter and use it in slot eligibility and sponsor dashboards.', '["Poor-quality sponsor suppressed from trust-sensitive surfaces", "Reason codes visible to admin", "Quality score feeds proof packet"]'::jsonb),
  ('community_proof_stack', 'community_intelligence', 'Community Proof Stack Ads', 'community_adgrid', 90, 'contract', 'Better ad trust and renewal by showing safe positive proof under sponsor placements.', 'Reddit is using positive community posts under ads; HC can do this more safely with verified heavy-haul context.', '["conversation_threads", "directory", "hc_ask", "sponsor_dashboard"]'::jsonb, '["reviews", "thread_answers", "votes", "helpful_marks", "clip_comments", "claims", "jobs_completed"]'::jsonb, '{"products": ["community pain point report", "trusted vendor signal"]}'::jsonb, '["threads/comments/reviews/profiles"]'::jsonb, '["proof candidate extractor", "moderation gate", "proof block renderer"]'::jsonb, '{"proof_types": ["verified review", "completed job count", "response speed", "badge", "most helpful answer", "clip/testimonial snippet", "directory rank", "local market presence"]}'::jsonb, '["No defamatory/unsafe content", "No private messages", "Sponsor cannot fabricate proof"]'::jsonb, 'Build proof-block pipeline that only surfaces safe, verified, sponsor-relevant proof.', '["Proof block shows source/type/date", "Admin can suppress proof item", "Proof performance is tracked"]'::jsonb),
  ('ai_campaign_builder', 'self_serve_ai_campaign_builder', 'Self-Serve AI AdGrid Campaign Builder', 'adgrid_self_serve', 94, 'contract', 'Unlock long-tail sponsors across 120 countries without manual ad ops.', 'Meta and Google are moving toward agentic/automated ad creation; HC should own this in heavy haul.', '["advertiser_dashboard", "sponsor_checkout", "directory_claim_flow"]'::jsonb, '["campaign_created", "creative_generated", "budget_set", "approval", "launch", "performance"]'::jsonb, '{"products": ["advertiser demand report", "market price sensitivity"]}'::jsonb, '["advertiser_accounts", "hc_adgrid_campaign", "hc_adgrid_ab_tests", "billing/orders"]'::jsonb, '["campaign wizard", "recommendation engine", "creative review queue", "auto-generated package summary"]'::jsonb, '{"inputs": ["business type", "service area", "budget", "goal", "phone", "offer", "target role", "country/state/city/corridor"], "outputs": ["directory ad", "call ad", "conversation ad", "newsletter slot", "clip sponsor card", "HC ASK sponsored answer", "retargeting audience", "proof packet plan"]}'::jsonb, '["No auto-launch without approval by default", "Brand safety checks required", "No unrealistic guarantee claims"]'::jsonb, 'Build wizard and backend spec that maps sponsor inputs to campaign package recommendations.', '["Sponsor can create package in plain language", "System recommends surfaces/budget/bid/floor", "Sponsor reviews generated copy before launch"]'::jsonb),
  ('similar_market_expansion', 'self_serve_ai_campaign_builder', 'Similar Market Expansion', 'growth_intelligence', 88, 'contract', 'Upsell sponsors into similar high-intent markets; clone winners globally.', 'Meta lookalikes/general targeting are broad; HC can do niche-specific market similarity.', '["sponsor_dashboard", "admin_growth_console", "data_product_portal"]'::jsonb, '["market_performance", "category_demand", "call_intent", "supply_gap", "sponsor_roi"]'::jsonb, '{"products": ["similar market expansion report", "sponsor opportunity map"]}'::jsonb, '["market/demand/corridor/country data tables"]'::jsonb, '["market similarity scoring", "clone recommendation jobs"]'::jsonb, '{"similarity_factors": ["role demand", "category demand", "corridor behavior", "call conversion", "supply scarcity", "country maturity", "language/regulatory fit"]}'::jsonb, '["Show confidence and why", "Do not recommend illegal/ineligible markets"]'::jsonb, 'Generate recommended clone markets for campaigns, clips, data products, and category pages.', '["Dashboard returns top similar markets", "Each recommendation has reasons/confidence", "Can convert recommendation into Codex task/campaign draft"]'::jsonb),
  ('breakout_clip_asset_ledger', 'media_factory_breakout_clips', 'Breakout Clip Asset Ledger', 'media_factory_adgrid', 94, 'contract', 'Each clip becomes sponsor inventory, retargeting seed, SEO/AEO asset, training snippet, and data signal.', 'Breakout clips were already planned; this formalizes the revenue and signal loop.', '["clips", "video_seo_pages", "directory", "newsletter", "threads", "retargeting"]'::jsonb, '["clip_view", "watch_percent", "cta_click", "sponsor_click", "share", "save", "comment", "lead", "claim"]'::jsonb, '{"products": ["clip trend report", "topic demand heatmap", "sponsor category alert"]}'::jsonb, '["hc_operator_videos", "hc_video_channel_registry", "hc_video_series_registry", "hc_video_seo_rules"]'::jsonb, '["clip metadata ledger", "clip-to-sponsor routing", "clip-to-data-signal adapter"]'::jsonb, '{"metadata": ["topic", "role", "country", "corridor", "sponsor_category", "hook", "guest/operator", "format", "length", "CTA", "linked directory/category/glossary"]}'::jsonb, '["Disclose sponsored clips", "Respect rights/permissions", "Do not use private footage without consent"]'::jsonb, 'Make all clips trackable, taggable, sponsorable, and linkable to data products.', '["Clip has performance ledger", "Sponsor package can include clip family", "High-performing clip creates market/topic signal"]'::jsonb),
  ('media_factory_rendering_stack', 'media_factory_breakout_clips', 'HyperFrames + Remotion Rendering Stack', 'media_factory', 86, 'contract', 'Reduce creative cost and create thousands of localized sponsor/data/report assets.', 'AdGrid needs cheap creative variants at country/city/category scale.', '["adgrid_creatives", "sponsor_proof_packets", "clips", "reports", "newsletter"]'::jsonb, '["asset_rendered", "variant_tested", "asset_used", "asset_won"]'::jsonb, '{"products": ["visual data report exports", "benchmark video snippets"]}'::jsonb, '["storage/media tables if present"]'::jsonb, '["render job contracts", "template registry", "asset provenance"]'::jsonb, '{"heygen_minimal_use": ["trust intros", "sponsor explainer", "training intro"], "hyperframes_use": ["stat cards", "sponsor cards", "leaderboard clips", "market pulse snippets", "proof visuals"], "remotion_use": ["recurring series", "weekly market reports", "country readiness videos", "sponsor packages", "AMA recaps"]}'::jsonb, '["AdGrid stores refs; Media Factory renders", "Do not overuse expensive avatar video", "Template/version provenance required"]'::jsonb, 'Create renderer abstraction and template registry; connect outputs to AdGrid asset references.', '["Asset records include engine/template/version", "AdGrid can select media asset by ID", "Proof packet can include rendered visual"]'::jsonb),
  ('weekly_adgrid_retro', 'adgrid_motion_intelligence', 'Weekly AdGrid Retro', 'growth_intelligence', 87, 'contract', 'Turns performance into next week revenue moves.', 'Motion-style retros force cloning winners and killing losers.', '["admin_dashboard", "sales_dashboard", "sponsor_dashboard"]'::jsonb, '["all_adgrid_events", "data_product_sales", "sponsor_renewals"]'::jsonb, '{"products": ["weekly market intelligence brief"]}'::jsonb, '["adgrid performance views", "data product views"]'::jsonb, '["weekly retro generator", "next-action queue"]'::jsonb, '{"sections": ["winning ads", "winning house ads", "winning markets", "weak spots", "money left", "sponsors to pitch", "data products to create", "clips to produce", "prices to raise"]}'::jsonb, '["Show confidence/freshness", "Do not over-claim causality"]'::jsonb, 'Create weekly retro view/API and admin UI component.', '["Retro produces ranked actions", "Actions can become Codex tasks", "Report includes evidence links"]'::jsonb),
  ('sponsor_proof_packets_all_products', 'sponsor_proof_packets', 'Sponsor Proof Packets Across Every Paid Product', 'adgrid', 93, 'contract', 'Renewal and upsell engine for every AdGrid product.', 'Sponsors buy again when proof is obvious.', '["sponsor_dashboard", "sales_admin", "email/pdf export later"]'::jsonb, '["impressions", "clicks", "calls", "leads", "claims", "profile_visits", "clip_metrics", "market_lift"]'::jsonb, '{"products": ["sponsor ROI benchmarks", "category benchmarks"]}'::jsonb, '["hc_adgrid_ama_sponsorships", "hc_adgrid_campaign", "hc_adgrid_outcome_events"]'::jsonb, '["universal proof packet objects", "renewal recommender", "screenshot/placement evidence store"]'::jsonb, '{"packet_fields": ["where ads showed", "screenshots/previews", "impressions", "clicks", "calls", "leads", "profile visits", "claim assists", "best creative", "worst creative", "next market", "next package", "missed surfaces"]}'::jsonb, '["Truthful metrics only", "Aggregate private behavior", "Clear attribution model"]'::jsonb, 'Expand proof packet concept beyond AMA into all sponsor products.', '["Each paid product maps to a proof packet template", "Sponsor dashboard shows current proof", "Renewal recommendation generated"]'::jsonb),
  ('category_location_engine', 'category_location_engine_120', 'Category × Location Monetization Engine', 'directory_data_adgrid', 91, 'contract', 'Every market cell can monetize via SEO, directory claims, sponsor slots, call ads, data reports, and exclusivity.', 'HC has 120 countries; the core moat is owning category/location intent before Google/Yelp/directories do.', '["category_pages", "city_pages", "state_pages", "country_pages", "corridor_pages", "data_portal"]'::jsonb, '["page_views", "searches", "calls", "claims", "sponsor_buys", "supply_gap", "data_exports"]'::jsonb, '{"products": ["category scarcity index", "market readiness packet", "sponsor opportunity report"]}'::jsonb, '["country/city/market/directory tables", "seo pages", "hc_data_products"]'::jsonb, '["market cell scoring", "sponsor readiness badges", "category data product generator"]'::jsonb, '{"categories": ["pilot car companies", "permit services", "mobile repair", "radio installers", "secure parking", "oversize motels", "route surveyors", "insurance", "training", "equipment", "brokers", "staging yards"]}'::jsonb, '["Honest coverage labeling", "No fake supply", "Country legal gate"]'::jsonb, 'Build scoring and page/product generation based on category/location readiness.', '["Market cell has SEO readiness, sponsor readiness, data readiness", "Cells produce next actions", "Sponsors can buy eligible category/location packages"]'::jsonb),
  ('competitor_displacement_map', 'competitor_displacement_layer', 'Competitor Displacement Map', 'growth_intelligence', 89, 'contract', 'Steal budget ethically by identifying competitor gaps and pitching superior HC products.', 'Need to beat Google, Reddit, Facebook, Yellow Pages, freight boards, and niche directories before they own the heavy-haul vertical.', '["admin_growth_console", "sales_dashboard", "data_product_portal"]'::jsonb, '["public competitor observations", "search results", "ad libraries", "directory gaps", "sponsor feedback"]'::jsonb, '{"products": ["competitor gap report", "share-of-attention report"]}'::jsonb, '["competitor_intel", "hc_competitor_page_intelligence where present"]'::jsonb, '["competitor family playbooks", "gap score", "countermove recommendations"]'::jsonb, '{"families": ["search ads", "social/community", "local directories", "freight boards", "niche heavy-haul sites", "ad intelligence tools"]}'::jsonb, '["Use public/legal data only", "Extract patterns not copy", "Manual review for claims"]'::jsonb, 'Build competitor playbook UI and scoring jobs.', '["Each competitor family has gaps/countermoves", "Admin sees moat tasks", "Sales gets sponsor pitch angle"]'::jsonb),
  ('retargeting_recovery_audiences', 'retargeting_recovery_layer', 'Retargeting Recovery Audiences', 'retargeting', 82, 'contract', 'Recover abandoned claim, sponsor checkout, call intent, data product preview, and lead unlock behavior.', 'External networks are allowed only for retargeting; this turns leakage into recovery.', '["external_retargeting", "return_landing_pages"]'::jsonb, '["claim_abandon", "sponsor_checkout_abandon", "directory_visit", "data_preview", "lead_unlock_abandon", "clip_watch"]'::jsonb, '{"products": ["retargeting lift benchmark"]}'::jsonb, '["pixel/analytics/event layer", "consent manager"]'::jsonb, '["audience eligibility rules", "suppression rules", "return CTAs"]'::jsonb, '{"audiences": ["abandoned claim", "sponsor checkout", "directory category visitor", "HC ASK commercial intent", "data product preview", "lead unlock intent", "clip topic viewer"]}'::jsonb, '["Consent/platform policy gate", "No sensitive category targeting", "Suppression after conversion"]'::jsonb, 'Define retargeting audience exports and return-to-HC landing intents; do not create external inventory.', '["Each audience has eligibility/suppression", "External campaign CTA returns to HC", "Conversions dedupe against internal events"]'::jsonb),
  ('data_product_self_serve_portal', 'data_product_self_serve_portal', 'Self-Serve Data Product Portal', 'data_monetization', 97, 'contract', 'Sell reports, API access, bundles, exports, and benchmarks across all 120 countries.', 'User said this is one of first three products live with AdGrid.', '["data_portal", "account_dashboard", "checkout", "api_keys", "exports"]'::jsonb, '["data_preview", "purchase", "export_job", "api_call", "renewal"]'::jsonb, '{"primary": "core revenue product"}'::jsonb, '["hc_data_products", "hc_data_bundles", "hc_data_product_export_jobs", "hc_data_api_keys", "v_data_monetization_command_center"]'::jsonb, '["catalog UI", "preview gating", "checkout integration", "export/API flows", "freshness/confidence labels"]'::jsonb, '{"features": ["catalog", "country/category/corridor filters", "sample rows", "coverage meter", "legal gate", "purchase", "export job", "API key", "bundle upsell"]}'::jsonb, '["No raw PII exports", "Coverage/freshness/provenance visible", "Country legal gate"]'::jsonb, 'Implement portal using existing data spine and these blueprints as catalog source.', '["Buyer can browse/preview/buy/export", "API keys tied to entitlements", "Legal gate blocks ineligible data"]'::jsonb),
  ('partner_program_adgrid_feed', 'category_location_engine_120', 'Partner Program Feed Into AdGrid', 'partners_adgrid', 80, 'contract', 'Partners become verified sponsor supply for category/location inventory.', 'Partner program can fill inventory and strengthen proof/data products.', '["partner_marketplace", "directory", "adgrid", "data_portal"]'::jsonb, '["partner_application", "verification", "sponsor_purchase", "lead_delivery", "renewal"]'::jsonb, '{"products": ["partner supply coverage report", "category availability report"]}'::jsonb, '["partner/provider/sponsor tables where present"]'::jsonb, '["partner-to-sponsor packaging", "verified partner badge mapping"]'::jsonb, '{"partner_types": ["permit services", "insurance", "radio installers", "equipment suppliers", "training providers", "route surveyors", "mobile mechanics", "parking yards", "brokers", "compliance consultants"]}'::jsonb, '["Verification before trust badge", "Disclosure for sponsored status"]'::jsonb, 'Map verified partners into eligible AdGrid sponsor/category inventory.', '["Partner can become sponsor inventory", "Verified status affects quality score", "Partner coverage feeds data products"]'::jsonb)
