insert into hc_build.platform_inspiration_specs (inspiration_key, platform_name, pattern_name, current_signal, haul_command_adaptation, do_not_copy, codex_translation, source_urls, priority) values
  ('google_ai_search_ads', 'Google Ads/Search', 'Ads in AI Overviews and AI Mode', 'Google Marketing Live 2025 announced ads expanding in AI Overviews to desktop and ads coming to AI Mode.', 'Create Sponsored HC ASK Answers with clear labels, organic answer preservation, verified providers, call/quote CTAs, and event capture.', 'Do not create generic web-wide search ads; keep inventory inside HC ASK/directory/search surfaces.', '{"features": ["sponsored_hc_ask_answers", "direct_offers", "smart_slot_assembly"], "required_labels": ["Sponsored", "Verified where applicable"]}'::jsonb, '["https://blog.google/products/ads-commerce/google-marketing-live-2025/"]'::jsonb, 100),
  ('google_call_assets', 'Google Ads', 'Call assets and call reporting', 'Google call assets add phone numbers, tap/click-to-call, business-hour scheduling, forwarding/reporting, and call conversion measurement.', 'Build Heavy Haul Call Ads, qualified call billing, missed-call recovery, and call proof packets with heavy-haul route/category context.', 'Do not expose raw caller data as a sellable data product; obey recording/consent laws.', '{"events": ["call_tap", "call_connected", "qualified_call", "missed_call"], "features": ["heavy_haul_call_ads", "qualified_call_leads"]}'::jsonb, '["https://support.google.com/google-ads/answer/2453991?hl=en"]'::jsonb, 100),
  ('google_ai_max_smart_bidding', 'Google Ads', 'AI Max and Smart Bidding Exploration', 'Google positioned AI Max and Smart Bidding Exploration as ways to find untapped, less obvious, high-performing search opportunities.', 'Build Similar Market Expansion and Smart Slot Assembly to find overlooked heavy-haul markets/categories/corridors before competitors.', 'Do not make opaque black-box bidding without reason codes; HC must explain market recommendations.', '{"features": ["similar_market_expansion", "weekly_adgrid_retro", "creative_pattern_library"]}'::jsonb, '["https://blog.google/products/ads-commerce/google-marketing-live-2025/"]'::jsonb, 94),
  ('reddit_community_intelligence', 'Reddit', 'Community Intelligence and Conversation Summary Add-ons', 'Reddit announced ad tools using Community Intelligence and positive posts under ads, turning conversations into structured marketing insight.', 'Build Heavy Haul Community Intelligence and Sponsor Proof Stack using HC threads, reviews, Q&A, clips, and verified proof.', 'Do not scrape/private-message communities or fabricate social proof; only safe, moderated, allowed proof.', '{"features": ["community_proof_stack", "community_intelligence"], "proof_types": ["reviews", "helpful answers", "verified badges", "completed jobs"]}'::jsonb, '["https://www.theverge.com/news/687604/reddit-positive-posts-ads-conversation-summary-add-ons-cannes-lions"]'::jsonb, 93),
  ('meta_ai_ad_automation', 'Meta/Facebook/Instagram', 'AI-powered ad creation and targeting automation', 'Reporting says Meta is moving toward AI systems that generate full campaigns from product image/budget and personalize ads across its apps.', 'Build self-serve AI Campaign Builder for heavy-haul sponsors; require approval and brand-safety controls.', 'Do not allow uncontrolled AI creative drift or invisible settings that auto-change sponsor ads.', '{"features": ["ai_campaign_builder", "media_factory_rendering_stack"], "guardrails": ["review before launch", "brand safety checks", "reason codes"]}'::jsonb, '["https://www.reuters.com/business/media-telecom/meta-aims-fully-automate-advertising-with-ai-by-2026-wsj-reports-2025-06-02/"]'::jsonb, 90),
  ('yellow_pages_local_category', 'Yellow Pages / Yelp / Local directories', 'Category + location + phone monetization', 'Local directory economics are still built on category/location intent, phone calls, sponsored listings, and pay-per-call style value.', 'Build Yellow Pages 100X: category-location pages, call ads, sponsor slots, category scarcity indexes, and local proof.', 'Do not become generic local listings; specialize in heavy haul roles, corridors, permits, escorts, route support, and 120-country readiness.', '{"features": ["category_location_engine", "heavy_haul_call_ads"]}'::jsonb, '[]'::jsonb, 88),
  ('motion_creative_intelligence', 'Motion', 'Creative performance intelligence and weekly retros', 'Motion-style workflow connects creative asset, performance, tags, patterns, and next actions.', 'AdGrid Motion Intelligence should score internal ads, house ads, clips, sponsor packages, and market patterns.', 'Do not make this DTC-only creative analytics; it must include directory/load/community/data signals.', '{"features": ["creative_pattern_library", "weekly_adgrid_retro", "sponsor_proof_packets_all_products"]}'::jsonb, '["https://motionapp.com/"]'::jsonb, 87),
  ('breakout_clips_to_inventory', 'Breakout Clips / Short-form content systems', 'Clips as assets, ads, proof, and signals', 'Breakout clips can become recurring clip series, sponsor cards, retargeting audiences, SEO pages, training modules, and trend signals.', 'Make every clip a ledgered, sponsorable, AdGrid-measured, data-product-feeding asset.', 'Do not treat clips as vanity content without routing/CTA/proof/data capture.', '{"features": ["breakout_clip_asset_ledger", "media_factory_rendering_stack"]}'::jsonb, '[]'::jsonb, 86)
on conflict (inspiration_key) do update set platform_name=excluded.platform_name, pattern_name=excluded.pattern_name, current_signal=excluded.current_signal, haul_command_adaptation=excluded.haul_command_adaptation, do_not_copy=excluded.do_not_copy, codex_translation=excluded.codex_translation, source_urls=excluded.source_urls, priority=excluded.priority;

