insert into hc_build.competitor_displacement_targets (target_key, competitor_family, competitor_name, what_they_win, what_they_lack, haul_command_countermove, moats_to_build, signals_to_monitor, products_to_launch, priority, codex_directive) values
  ('google_ads_search', 'search_ads', 'Google Ads / Google Search', 'Owns broad commercial search intent, local call extensions, AI search discovery.', 'Does not know heavy-haul operational context, provider trust, load/corridor needs, or niche support gaps.', 'Own HC ASK sponsored answers, directory/category/location pages, call ads, quality score, and route/corridor intent.', '["internal heavy-haul intent graph", "verified provider trust", "call quality", "corridor/category data products"]'::jsonb, '["AI Mode ads", "AI Overviews ad formats", "call assets", "local service ad categories"]'::jsonb, '["sponsored_hc_ask_answers", "heavy_haul_call_ads", "category_location_engine"]'::jsonb, 100, 'Build public/legal monitoring and HC countermove recommendations for this competitor family.'),
  ('reddit_community', 'community_ads', 'Reddit', 'Owns authentic conversations and community proof.', 'Not purpose-built for transaction-ready heavy haul search, verified providers, or call/quote routing.', 'Build HC Community Intelligence, proof stack ads, sponsored expert answers, and AMA-to-clips-to-data loops.', '["verified industry proof", "moderated expert sessions", "thread-native transaction CTAs"]'::jsonb, '["community sentiment", "positive proof under ads", "AMA sponsorships"]'::jsonb, '["community_proof_stack", "community_intelligence", "breakout_clip_asset_ledger"]'::jsonb, 94, 'Build public/legal monitoring and HC countermove recommendations for this competitor family.'),
  ('meta_facebook_groups', 'social_ads', 'Facebook / Meta / Groups', 'Owns attention, retargeting, groups, click-to-message behavior, and AI ad automation.', 'Groups are fragmented, noisy, not structured into data products, and weak at verified directory intent.', 'Use Facebook only for retargeting/recovery; build AI Campaign Builder and HC-owned community/directory loops.', '["first-party directory intent", "structured category/location graph", "quality score", "proof packets"]'::jsonb, '["AI campaign automation", "click-to-message patterns", "group lead behavior"]'::jsonb, '["ai_campaign_builder", "retargeting_recovery_audiences"]'::jsonb, 90, 'Build public/legal monitoring and HC countermove recommendations for this competitor family.'),
  ('yellow_pages_yelp', 'local_directories', 'Yellow Pages / Yelp / Local Directories', 'Own local category/location search, sponsored profiles, reviews, and phone lead economics.', 'Too generic; lacks oversize/heavy-haul roles, corridors, permits, escort details, and international readiness.', 'Build Yellow Pages 100X for heavy haul: category/location/corridor pages plus call ads and scarcity data.', '["120-country category/location/corridor graph", "route support taxonomy", "heavy-haul trust signals"]'::jsonb, '["sponsored listings", "pay-per-call", "profile upgrades"]'::jsonb, '["category_location_engine", "heavy_haul_call_ads"]'::jsonb, 88, 'Build public/legal monitoring and HC countermove recommendations for this competitor family.'),
  ('freight_boards', 'freight_marketplaces', 'DAT / Truckstop / Load Boards', 'Own broker/carrier load-matching attention and freight analytics.', 'Do not own full support ecosystem: pilot cars, permits, route surveyors, parking, repair, training, sponsor media, and community proof.', 'Position HC as the support layer around heavy haul loads and sell support demand intelligence.', '["support-service ecosystem data", "route/corridor support gaps", "directory + load intent"]'::jsonb, '["lane intelligence", "market benchmarks", "load demand"]'::jsonb, '["route_support_demand_feed", "corridor_demand_heatmap"]'::jsonb, 87, 'Build public/legal monitoring and HC countermove recommendations for this competitor family.'),
  ('niche_directories', 'niche_heavy_haul_sites', 'Pilot car / permit / oversize directories', 'Own small pockets of niche SEO and provider lists.', 'Fragmented, stale, often no ad tech, weak data products, no 120-country system.', 'Outbuild with freshness, proof, call ads, category scarcity, and sponsor dashboards.', '["freshness/provenance", "verified trust", "self-serve sponsor + data products"]'::jsonb, '["service categories", "quote flows", "directory SEO"]'::jsonb, '["category_location_engine", "sponsor_proof_packets_all_products"]'::jsonb, 86, 'Build public/legal monitoring and HC countermove recommendations for this competitor family.'),
  ('ai_ad_tools', 'ad_intelligence_tools', 'Motion / Omneky / Creatify / AdCreative.ai', 'Own creative generation, testing, and creative analytics.', 'Generic across industries; do not own heavy-haul inventory, calls, directory, or market data.', 'Use their workflows as inspiration but build HC-native creative intelligence and media factory.', '["closed-loop inventory + data products", "industry context", "call/proof/quality signals"]'::jsonb, '["creative variants", "performance tags", "weekly retros", "agentic campaign creation"]'::jsonb, '["creative_pattern_library", "media_factory_rendering_stack", "weekly_adgrid_retro"]'::jsonb, 84, 'Build public/legal monitoring and HC countermove recommendations for this competitor family.')
on conflict (target_key) do update set competitor_family=excluded.competitor_family, competitor_name=excluded.competitor_name, what_they_win=excluded.what_they_win, what_they_lack=excluded.what_they_lack, haul_command_countermove=excluded.haul_command_countermove, moats_to_build=excluded.moats_to_build, signals_to_monitor=excluded.signals_to_monitor, products_to_launch=excluded.products_to_launch, priority=excluded.priority, codex_directive=excluded.codex_directive;

insert into hc_build.missing_money_radar (opportunity_key, opportunity_name, product_area, priority, revenue_lever, current_gap, aggressive_move, required_signals, expected_outputs, codex_directive, acceptance_criteria) values
  ('qualified_call_ads', 'Qualified Call Ads', 'adgrid', 100, 'Pay-per-qualified-call and urgent call packages', 'Clicks are weaker than real phone demand for many service categories.', 'Launch call-first AdGrid products with qualified-call billing and missed-call recovery.', '["call_tap", "call_connected", "duration", "business_hours", "outcome"]'::jsonb, '["call sponsor packages", "call intent data product", "proof packet"]'::jsonb, 'Implement Heavy Haul Call Ads first because service providers buy calls, not vanity clicks.', '["Has measurable event loop", "Has sponsor/data monetization path", "Has admin next action"]'::jsonb),
  ('unsold_inventory_house_ads', 'Unsold Inventory House-Ad Optimization', 'adgrid_growth', 98, 'Turn unsold slots into claims, upgrades, data sales, and sponsor pitches.', 'Unsold inventory can become dead space if treated as filler.', 'Rotate house ads by goal and optimize them like paid campaigns.', '["slot_empty", "surface_context", "house_ad_impression", "claim/signup/purchase"]'::jsonb, '["claim ads", "data product ads", "sponsor this market ads", "lead unlock ads"]'::jsonb, 'Build house-ad optimizer and make unsold inventory revenue-seeking.', '["Has measurable event loop", "Has sponsor/data monetization path", "Has admin next action"]'::jsonb),
  ('sponsor_proof_renewals', 'Sponsor Proof → Renewal Engine', 'adgrid_sales', 96, 'Renewals and upsells from proof packets.', 'Sponsors churn if they cannot see value.', 'Generate proof packets and next-buy recommendations automatically.', '["impressions", "clicks", "calls", "leads", "profile_views", "market_gap"]'::jsonb, '["proof packet", "next market upsell", "renewal score"]'::jsonb, 'Make proof packets universal and visible in sponsor dashboard.', '["Has measurable event loop", "Has sponsor/data monetization path", "Has admin next action"]'::jsonb),
  ('hc_ask_commercial_answers', 'HC ASK Commercial Intent Slots', 'search_ai', 95, 'Sponsored answer slots at moment of need.', 'AI search can answer heavy-haul questions without monetization if not structured now.', 'Add clearly labeled sponsor cards to commercial answers.', '["query_intent", "answer_view", "sponsor_click", "call_tap"]'::jsonb, '["sponsored answer product", "AI-search demand data"]'::jsonb, 'Build answer inventory before Google dominates AI search behavior.', '["Has measurable event loop", "Has sponsor/data monetization path", "Has admin next action"]'::jsonb),
  ('direct_offers', 'Direct Offers at Intent Moment', 'offers', 92, 'Offer claims, sponsor purchases, claim upgrades, and partner sales.', 'Sponsors need actionable offers, not just banners.', 'Allow market/category/time-bound direct offers with transparent terms.', '["offer_view", "offer_click", "offer_claim"]'::jsonb, '["offer benchmarks", "sponsor sales"]'::jsonb, 'Create direct offer object and eligible surfaces.', '["Has measurable event loop", "Has sponsor/data monetization path", "Has admin next action"]'::jsonb),
  ('category_exclusivity', 'Category/Location Exclusivity', 'directory_adgrid', 91, 'Premium exclusive sponsor packages by category/market.', 'High-value categories may be underpriced without scarcity packaging.', 'Sell limited exclusive or semi-exclusive sponsor slots with proof and fairness rules.', '["category_demand", "market_supply", "slot_inventory", "sponsor_competition"]'::jsonb, '["exclusive sponsor slots", "floor price recommendations"]'::jsonb, 'Build scarcity pricing and exclusivity guardrails.', '["Has measurable event loop", "Has sponsor/data monetization path", "Has admin next action"]'::jsonb),
  ('data_preview_to_checkout', 'Data Product Preview → Checkout Recovery', 'data_monetization', 90, 'Convert data-product previews into purchases/API subscriptions.', 'People may preview reports and leave without buying.', 'Track preview intent and retarget/recover inside/outside HC.', '["data_preview", "preview_depth", "checkout_abandon"]'::jsonb, '["retargeting audience", "sales alert", "bundle offer"]'::jsonb, 'Connect data previews to checkout and retargeting recovery.', '["Has measurable event loop", "Has sponsor/data monetization path", "Has admin next action"]'::jsonb),
  ('breakout_clip_sponsorships', 'Breakout Clip Sponsorship Packages', 'media_adgrid', 89, 'Sell clip families and topic sponsorships.', 'Clips can become vanity content if not monetized.', 'Make every clip taggable, sponsorable, and tied to directory/data outcomes.', '["clip_view", "topic", "cta_click", "sponsor_click"]'::jsonb, '["clip sponsorship", "topic demand data"]'::jsonb, 'Create clip sponsorship products and proof packet integration.', '["Has measurable event loop", "Has sponsor/data monetization path", "Has admin next action"]'::jsonb),
  ('similar_market_upsells', 'Similar Market Upsells', 'growth_intelligence', 87, 'Clone sponsor wins into similar markets.', 'A sponsor winning in one state/country may not know where to expand next.', 'Recommend similar markets with confidence and one-click campaign clone draft.', '["campaign_performance", "market_similarity", "category_demand"]'::jsonb, '["upsell recommendations", "clone campaign drafts"]'::jsonb, 'Build similar market expansion engine.', '["Has measurable event loop", "Has sponsor/data monetization path", "Has admin next action"]'::jsonb),
  ('partner_supply_packages', 'Verified Partner Sponsor Supply', 'partners_adgrid', 84, 'Turn partners into sponsor inventory and marketplace supply.', 'Partners may exist without being packaged into AdGrid/data products.', 'Map partner types into category/location packages and proof badges.', '["partner_verified", "category_supply", "market_gap"]'::jsonb, '["partner marketplace packages", "supply coverage data"]'::jsonb, 'Connect partner program to AdGrid inventory and data coverage.', '["Has measurable event loop", "Has sponsor/data monetization path", "Has admin next action"]'::jsonb),
  ('competitor_gap_pitches', 'Competitor Gap Sales Pitches', 'growth_sales', 83, 'Use competitor gaps to close sponsors.', 'Sales may not know why HC beats Google/Yelp/Facebook/niche directories in a category.', 'Generate pitch cards from competitor displacement map.', '["competitor_gap", "market_demand", "sponsor_fit"]'::jsonb, '["sales cards", "counter-positioning"]'::jsonb, 'Build sales-ready competitor displacement cards.', '["Has measurable event loop", "Has sponsor/data monetization path", "Has admin next action"]'::jsonb)
on conflict (opportunity_key) do update set opportunity_name=excluded.opportunity_name, product_area=excluded.product_area, priority=excluded.priority, revenue_lever=excluded.revenue_lever, current_gap=excluded.current_gap, aggressive_move=excluded.aggressive_move, required_signals=excluded.required_signals, expected_outputs=excluded.expected_outputs, codex_directive=excluded.codex_directive, acceptance_criteria=excluded.acceptance_criteria;

