insert into hc_build.launch_phase_gates (gate_key, launch_phase, gate_name, product_area, priority, pass_condition, required_objects, required_metrics, failure_response, codex_directive) values
  ('adgrid_internal_boundary_gate', 'phase_1', 'AdGrid Internal Boundary Gate', 'adgrid', 100, 'All AdGrid product copy and code paths define inventory as HC-owned surfaces only; external is retargeting-only.', '["hc_build.codex_programs", "adgrid product constants"]'::jsonb, '["No external publisher inventory records"]'::jsonb, 'Block launch until copy and constants are fixed.', 'Add tests/admin warnings to prevent external-network drift.'),
  ('data_privacy_gate', 'phase_1', 'Data Product Privacy Gate', 'data_monetization', 100, 'Every data product has privacy gate, aggregation rule, k-anonymity, freshness, confidence, and provenance labels.', '["hc_build.adgrid_event_policy", "existing v_data_product_legal_gate if present"]'::jsonb, '["zero PII exports", "k threshold pass"]'::jsonb, 'Block export and show insufficient coverage/legal warning.', 'Implement gate before self-serve export/API launch.'),
  ('call_ads_gate', 'phase_1', 'Call Ads Launch Gate', 'adgrid', 98, 'Call events, business-hour schedule, qualification rule, proof packet, and legal recording gate exist.', '["call event capture", "call proof packet blueprint"]'::jsonb, '["call_tap", "qualified_call", "missed_call"]'::jsonb, 'Launch tap-to-call without recording if recording consent gate is not ready.', 'Build call ads as core launch product.'),
  ('hc_ask_sponsored_gate', 'phase_1', 'Sponsored HC ASK Gate', 'search_ai', 96, 'Sponsored label, organic answer fallback, proof stack, and hide/report events exist.', '["answer slot policy", "sponsored answer components"]'::jsonb, '["sponsored_answer_view", "sponsored_answer_click", "hide_report"]'::jsonb, 'Do not launch paid answer slots until labeling and quality controls pass.', 'Build clear sponsored answer policy.'),
  ('data_portal_gate', 'phase_1', 'Self-Serve Data Portal Gate', 'data_monetization', 95, 'Catalog, preview, checkout, entitlement, export/API route, and legal gate are wired.', '["hc_data_products", "hc_data_product_export_jobs", "hc_data_api_keys"]'::jsonb, '["preview_to_purchase", "export_job_complete"]'::jsonb, 'Launch admin-assisted sales first if checkout/export not ready.', 'Build portal around existing data spine.'),
  ('proof_packet_gate', 'phase_1', 'Proof Packet Gate', 'adgrid_sales', 90, 'Each paid product has at least one proof packet template and renewal recommendation.', '["hc_build.proof_packet_blueprints"]'::jsonb, '["proof_packet_generated", "renewal_recommendation"]'::jsonb, 'Do not sell premium packages without proof plan.', 'Wire metrics into sponsor dashboard.')
on conflict (gate_key) do update set launch_phase=excluded.launch_phase, gate_name=excluded.gate_name, product_area=excluded.product_area, priority=excluded.priority, pass_condition=excluded.pass_condition, required_objects=excluded.required_objects, required_metrics=excluded.required_metrics, failure_response=excluded.failure_response, codex_directive=excluded.codex_directive;

insert into hc_build.codex_build_tasks (task_key, feature_key, sprint, priority, task_type, task_title, action_summary, depends_on, db_objects, app_surfaces, acceptance_tests, monetization_impact, ready_for_codex, status) values
  ('task_001_scope_lock', 'adgrid_internal_scope_lock', 'phase_1', 100, 'product_contract', 'Enforce AdGrid internal-only scope', 'Add constants/copy/tests so AdGrid inventory is HC-owned only and outside activity is retargeting only.', '[]'::jsonb, '["hc_build.codex_programs"]'::jsonb, '["admin", "advertiser_dashboard"]'::jsonb, '["UI/copy never describes external publisher network", "Retargeting labeled separate from AdGrid"]'::jsonb, 'Prevents strategic drift and protects sales positioning.', true, 'open'),
  ('task_002_event_policy', 'dual_purpose_event_policy', 'phase_1', 100, 'data_architecture', 'Implement dual-purpose event policy', 'Create aggregate event adapters so events feed ad optimization and legal data products.', '["task_001_scope_lock"]'::jsonb, '["hc_build.adgrid_event_policy", "existing adgrid events"]'::jsonb, '["backend", "data_portal"]'::jsonb, '["Each event maps to privacy/revenue/data uses", "Exports enforce k-anonymity"]'::jsonb, 'Turns AdGrid into data monetization engine.', true, 'open'),
  ('task_003_call_ads', 'heavy_haul_call_ads', 'phase_1', 99, 'product_build', 'Build Heavy Haul Call Ads MVP', 'Add call asset model, call CTA rendering, business-hours schedule, call event capture, and qualified-call proof.', '["task_002_event_policy"]'::jsonb, '["call event tables/adapters", "hc_build.proof_packet_blueprints"]'::jsonb, '["directory", "hc_ask", "mobile"]'::jsonb, '["Call tap tracked", "Business hours honored", "Qualified call rule configurable", "Proof packet receives call metrics"]'::jsonb, 'Creates high-value pay-per-call revenue.', true, 'open'),
  ('task_004_data_portal_catalog', 'data_product_self_serve_portal', 'phase_1', 98, 'product_build', 'Build self-serve data product catalog', 'Use blueprints to expose searchable catalog with previews, coverage, confidence, legal gate, checkout/export/API path.', '["task_002_event_policy"]'::jsonb, '["hc_data_products", "hc_data_bundles", "hc_data_product_export_jobs", "hc_data_api_keys", "hc_build.data_product_blueprints"]'::jsonb, '["data_portal"]'::jsonb, '["Preview works", "Legal gate blocks unsafe data", "Purchase/export path defined"]'::jsonb, 'Launches one of first-three products.', true, 'open'),
  ('task_005_hc_ask_sponsored', 'sponsored_hc_ask_answers', 'phase_1', 98, 'product_build', 'Build Sponsored HC ASK Answer slots', 'Add answer-slot policy, sponsor matching, label, proof block, call/quote CTA, and event logging.', '["task_001_scope_lock", "task_002_event_policy"]'::jsonb, '["hc_build.adgrid_surface_taxonomy", "hc_build.adgrid_event_policy"]'::jsonb, '["hc_ask", "search"]'::jsonb, '["Sponsored label visible", "Organic answer preserved", "Events captured", "Hide/report available"]'::jsonb, 'Captures AI-search commercial intent before Google owns it.', true, 'open'),
  ('task_006_quality_score', 'heavy_haul_quality_score', 'phase_1', 97, 'ranking_trust', 'Build Heavy Haul Ad Quality Score', 'Create quality score adapter using verification, reviews, response, relevance, complaints, and market fit.', '["task_002_event_policy"]'::jsonb, '["provider/trust/review tables", "adgrid campaigns"]'::jsonb, '["slot_assembly", "sponsor_dashboard"]'::jsonb, '["Poor sponsor suppressed", "Reason codes generated", "Score feeds proof/eligibility"]'::jsonb, 'Protects trust and improves ad performance.', true, 'open'),
  ('task_007_proof_packets', 'sponsor_proof_packets_all_products', 'phase_1', 96, 'reporting', 'Build universal sponsor proof packet engine', 'Generate proof packets for call ads, directory sponsors, HC ASK, clips, newsletters, and takeovers.', '["task_003_call_ads", "task_005_hc_ask_sponsored"]'::jsonb, '["hc_build.proof_packet_blueprints"]'::jsonb, '["sponsor_dashboard", "admin"]'::jsonb, '["Packet exists per product family", "Next-buy recommendation shown", "Metrics truthful/aggregate"]'::jsonb, 'Improves renewals and upsells.', true, 'open'),
  ('task_008_house_ads', 'smart_slot_assembly', 'phase_1', 95, 'growth', 'Optimize unsold inventory with house ads', 'When paid sponsor not available, rotate house ads for claims, data sales, sponsor market, lead unlocks, partner applications.', '["task_001_scope_lock"]'::jsonb, '["hc_adgrid_house_ad_templates", "hc_build.adgrid_surface_taxonomy"]'::jsonb, '["all_adgrid_surfaces"]'::jsonb, '["No empty monetizable slot", "House ad conversions tracked", "Winners get more allocation"]'::jsonb, 'Turns dead inventory into growth/revenue.', true, 'open'),
