  ('task_012_direct_offers', 'direct_offers', 'phase_1', 91, 'product_build', 'Build Direct Offers', 'Create offer object/rules for sponsor discounts, claim upgrades, market sponsorship, equipment/install/permit offers.', '["task_005_hc_ask_sponsored"]'::jsonb, '["offer model", "adgrid campaigns"]'::jsonb, '["hc_ask", "directory", "clips", "newsletter"]'::jsonb, '["Offer renders with terms/expiration", "Offer claim tracked", "Offer can target market/category"]'::jsonb, 'Adds purchase/lead actions inside intent surfaces.', true, 'open'),
