create or replace view hc_build.v_codex_priority_queue as
select
  t.priority,
  t.status,
  t.ready_for_codex,
  t.sprint,
  t.task_type,
  t.task_key,
  t.task_title,
  t.action_summary,
  f.feature_name,
  f.product_area,
  p.program_name,
  t.depends_on,
  t.db_objects,
  t.app_surfaces,
  t.acceptance_tests,
  t.monetization_impact
from hc_build.codex_build_tasks t
left join hc_build.codex_feature_specs f on f.feature_key = t.feature_key
left join hc_build.codex_programs p on p.program_key = f.program_key
where t.ready_for_codex = true
order by t.priority desc, t.task_key;
comment on view hc_build.v_codex_priority_queue is 'Codex should start here: ordered build queue for AdGrid/data monetization upgrades.';

create or replace view hc_build.v_adgrid_data_monetization_bridge as
select
  e.event_family,
  e.event_key,
  e.event_name,
  e.privacy_level,
  e.revenue_use,
  e.data_product_use,
  e.aggregation_rule,
  e.minimum_k_anonymity,
  e.required_fields,
  e.prohibited_fields
from hc_build.adgrid_event_policy e
order by e.event_family, e.event_key;
comment on view hc_build.v_adgrid_data_monetization_bridge is 'Event policy view showing how AdGrid events feed revenue and data products.';

create or replace view hc_build.v_missing_money_priority as
select
  priority,
  product_area,
  opportunity_key,
  opportunity_name,
  revenue_lever,
  current_gap,
  aggressive_move,
  required_signals,
  expected_outputs,
  codex_directive
from hc_build.missing_money_radar
order by priority desc, opportunity_key;
comment on view hc_build.v_missing_money_priority is 'Aggressive revenue opportunities ranked for Codex/product execution.';

create or replace view hc_build.v_adgrid_launch_command_center as
select
  p.priority as program_priority,
  p.program_key,
  p.program_name,
  p.product_area,
  p.status as program_status,
  p.launch_phase,
  count(f.feature_key) as feature_count,
  count(t.task_key) filter (where t.status = 'open') as open_task_count,
  max(t.priority) as top_task_priority,
  p.acceptance_summary
from hc_build.codex_programs p
left join hc_build.codex_feature_specs f on f.program_key = p.program_key
left join hc_build.codex_build_tasks t on t.feature_key = f.feature_key
where p.product_area in ('adgrid','data_monetization','search_ai','media_factory','community_data','growth_intelligence','directory_adgrid_data','retargeting')
group by p.priority, p.program_key, p.program_name, p.product_area, p.status, p.launch_phase, p.acceptance_summary
order by p.priority desc;
comment on view hc_build.v_adgrid_launch_command_center is 'Program-level progress map for AdGrid + data monetization + media/community/growth intelligence.';

create or replace view hc_build.v_data_product_launch_catalog as
select
  priority,
  launch_phase,
  data_product_key,
  product_name,
  product_family,
  buyer_personas,
  input_signals,
  output_formats,
  pricing_model,
  privacy_gate,
  self_serve_requirements,
  codex_directive
from hc_build.data_product_blueprints
order by priority desc, data_product_key;
comment on view hc_build.v_data_product_launch_catalog is 'Self-serve data product catalog blueprint ordered by launch priority.';

create or replace function hc_build.get_next_codex_tasks(limit_count integer default 20)
returns table (
  priority integer,
  task_key text,
  task_title text,
  product_area text,
  action_summary text,
  acceptance_tests jsonb,
  monetization_impact text
)
language sql
stable
as $$
  select
    q.priority,
    q.task_key,
    q.task_title,
    q.product_area,
    q.action_summary,
    q.acceptance_tests,
    q.monetization_impact
  from hc_build.v_codex_priority_queue q
  where q.status = 'open'
  order by q.priority desc, q.task_key
  limit greatest(limit_count, 1);
$$;
comment on function hc_build.get_next_codex_tasks(integer) is 'Convenience function for Codex: select * from hc_build.get_next_codex_tasks(20);';

commit;
